import{c as s,cG as n,cb as a,c8 as p,cf as e,cT as i,ce as t}from"./chunks/framework.BlkIsu1j.js";const l=JSON.parse('{"title":"第 32 章：高级工作流","description":"","frontmatter":{"title":"第 32 章：高级工作流","outline":"deep","layout":"doc","prev":"/ai/claudecodenew/31-efficiency-optimization","next":"/ai/claudecodenew/33-custom-extensions","date":"2026-05-30T10:00:00.000Z"},"headers":[],"relativePath":"ai/claudecodenew/32-advanced-workflows.md","filePath":"ai/claudecodenew/32-advanced-workflows.md","lastUpdated":1780121796000}'),r={id:"frontmatter-title",tabindex:"-1"};const o=s({name:"ai/claudecodenew/32-advanced-workflows.md"},[["render",function(s,l,o,d,c,h){return n(),a("div",null,[p("h1",r,[e(i(s.$frontmatter.title)+" ",1),l[0]||(l[0]=p("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":"Permalink to “{{ $frontmatter.title }}”"},"​",-1))]),l[1]||(l[1]=t('<p>第 31 章结束时我们说过：掌握了效率优化的四个维度，你已经建立了一套以 Claude Code 为核心的、可度量、可优化的开发工作流。但&quot;可优化&quot;不等于&quot;已优化到极致&quot;。</p><p>本章是第七篇&quot;精通篇&quot;的开篇。精通和熟练的区别在于：熟练的用户能把单个任务跑通；精通的用户能把一组任务<strong>编排</strong>起来，让多个工作流在隔离环境中并行推进，用自动化消除重复劳动，用 Plan 模式把&quot;边想边做&quot;变成&quot;先谋后动&quot;，甚至让 Claude Code 在自己离开工位时继续工作。</p><p>这些高级工作流不是少数人的&quot;黑魔法&quot;——它们都是 Claude Code 内置的能力。你只需要知道它们存在、知道在什么场景下该用哪个、知道怎么组合它们，就能从&quot;一个人 + 一个 AI 助手&quot;的线性工作模式，进化到&quot;一个人 + 一个 AI 团队&quot;的并行工作模式。</p><blockquote><p><strong>本章目标</strong>：掌握 Claude Code 六种高级工作流——Subagent 并行分发、Plan 模式分阶段开发、多会话并行、Git Worktree 隔离、Cron 定时自动化、Workflow 编排——并能在真实项目中根据场景选择和组合它们，构建属于自己的高效工作流体系。</p></blockquote><h2 id="_32-1-多-agent-协作-subagent" tabindex="-1">32.1 多 Agent 协作（Subagent） <a class="header-anchor" href="#_32-1-多-agent-协作-subagent" aria-label="Permalink to “32.1 多 Agent 协作（Subagent）”">​</a></h2><p>在效率优化那一章，我们提到过 Subagent 是并行策略的重要工具。但那只是&quot;用起来&quot;的层面。要真正精通 Subagent，你需要理解它的内部机制、知道什么时候该用什么时候不该用、以及如何编排多个 Subagent 协同完成复杂任务。</p><h3 id="什么是-subagent" tabindex="-1">什么是 Subagent <a class="header-anchor" href="#什么是-subagent" aria-label="Permalink to “什么是 Subagent”">​</a></h3><p>Subagent 是 Claude Code 的一种内置机制：主会话（你与 Claude Code 的对话）可以在需要时 spawn 出独立的子 Agent，每个子 Agent 拥有独立的上下文窗口和工具权限，去执行一个独立的子任务。完成后，子 Agent 将结果返回给主会话，主会话汇总并继续。</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>┌─────────────────────────────────────────────────────┐</span></span>\n<span class="line"><span>│                    主会话 (Main Session)              │</span></span>\n<span class="line"><span>│  ┌──────────────┐  ┌──────────────┐  ┌──────────────┐│</span></span>\n<span class="line"><span>│  │  Subagent 1  │  │  Subagent 2  │  │  Subagent 3  ││</span></span>\n<span class="line"><span>│  │              │  │              │  │              ││</span></span>\n<span class="line"><span>│  │ 独立上下文    │  │ 独立上下文    │  │ 独立上下文    ││</span></span>\n<span class="line"><span>│  │ 独立工具权限  │  │ 独立工具权限  │  │ 独立工具权限  ││</span></span>\n<span class="line"><span>│  │ 独立执行      │  │ 独立执行      │  │ 独立执行      ││</span></span>\n<span class="line"><span>│  │              │  │              │  │              ││</span></span>\n<span class="line"><span>│  │ 任务 A       │  │ 任务 B       │  │ 任务 C       ││</span></span>\n<span class="line"><span>│  └──────┬───────┘  └──────┬───────┘  └──────┬───────┘│</span></span>\n<span class="line"><span>│         │                 │                 │         │</span></span>\n<span class="line"><span>│         └─────────────────┴─────────────────┘         │</span></span>\n<span class="line"><span>│                           │                           │</span></span>\n<span class="line"><span>│                    汇总结果，继续主任务                  │</span></span>\n<span class="line"><span>└─────────────────────────────────────────────────────┘</span></span></code></pre></div><p>关键特征：</p><ul><li><strong>上下文隔离</strong>：每个 Subagent 有独立的上下文窗口，不会&quot;污染&quot;主会话的上下文。一个 Subagent 读取了 50 个文件，不会占用你主会话的 token 预算。</li><li><strong>并行执行</strong>：多个 Subagent 可以同时运行，总等待时间等于最慢的那个。</li><li><strong>单向通信</strong>：Subagent 执行完毕后将结果返回给主会话，但 Subagent 之间不能直接通信，也不能把中间状态共享给其他 Subagent。</li></ul><h3 id="什么时候该用-subagent" tabindex="-1">什么时候该用 Subagent <a class="header-anchor" href="#什么时候该用-subagent" aria-label="Permalink to “什么时候该用 Subagent”">​</a></h3><p>Subagent 不是&quot;越多越好&quot;。它最适合以下三种场景：</p><p><strong>场景一：真正独立的并行任务</strong></p><p>三个子任务互不依赖、不修改相同的文件、不需要共享中间状态。</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>✅ 适合 Subagent：</span></span>\n<span class="line"><span>  &quot;请用 Subagent 并行处理：</span></span>\n<span class="line"><span>   1. 重构 src/utils/format.ts（独立工具函数）</span></span>\n<span class="line"><span>   2. 补充 src/components/Button/ 的单元测试（独立组件）</span></span>\n<span class="line"><span>   3. 更新 README.md 中的 API 文档（独立文档）&quot;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>❌ 不适合 Subagent：</span></span>\n<span class="line"><span>  &quot;请用 Subagent 并行处理：</span></span>\n<span class="line"><span>   1. 创建 User 数据模型</span></span>\n<span class="line"><span>   2. 基于 User 模型创建 API 路由</span></span>\n<span class="line"><span>   3. 基于 API 路由创建前端页面&quot;</span></span>\n<span class="line"><span>  → 2 依赖 1，3 依赖 2，无法并行。用串行流水线。</span></span></code></pre></div><p><strong>场景二：大量独立的信息收集</strong></p><p>当你需要同时探查代码库的多个方面，每个探查互不依赖。</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&quot;请用 Subagent 并行探查以下信息：</span></span>\n<span class="line"><span> 1. 找出所有使用 deprecated API 的地方（Subagent: 代码扫描）</span></span>\n<span class="line"><span> 2. 分析 package.json 中所有过期依赖的最新版本（Subagent: 依赖分析）</span></span>\n<span class="line"><span> 3. 统计各模块的测试覆盖率（Subagent: 覆盖率统计）&quot;</span></span></code></pre></div><p><strong>场景三：多视角交叉验证</strong></p><p>同一个问题，从多个角度独立分析，然后汇总对比。</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&quot;请用 3 个 Subagent 独立审查 src/api/auth.ts 的安全性：</span></span>\n<span class="line"><span> 1. Subagent 1：从 OWASP Top 10 角度审查</span></span>\n<span class="line"><span> 2. Subagent 2：从数据流和输入验证角度审查</span></span>\n<span class="line"><span> 3. Subagent 3：从依赖库已知漏洞角度审查</span></span>\n<span class="line"><span> 汇总三个审查结果，标出共同发现的问题。&quot;</span></span></code></pre></div><h3 id="如何触发-subagent" tabindex="-1">如何触发 Subagent <a class="header-anchor" href="#如何触发-subagent" aria-label="Permalink to “如何触发 Subagent”">​</a></h3><p>Claude Code 会在以下情况<strong>自动决定</strong>使用 Subagent：</p><ul><li>你要求同时做多件独立的事情（&quot;同时...&quot;、&quot;一并...&quot;）</li><li>需要大规模代码搜索，而搜索任务可以被分解为多个独立方向</li><li>需要多个独立视角的分析</li></ul><p>你也可以<strong>明确指令</strong>：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&quot;用 Subagent 并行处理以下三个任务：&quot;</span></span>\n<span class="line"><span>&quot;请启动一个 Subagent 专门负责代码搜索，另一个负责实现&quot;</span></span>\n<span class="line"><span>&quot;对这个文件做安全审查，用两个 Subagent 从不同角度独立分析&quot;</span></span></code></pre></div><h3 id="subagent-的隔离机制详解" tabindex="-1">Subagent 的隔离机制详解 <a class="header-anchor" href="#subagent-的隔离机制详解" aria-label="Permalink to “Subagent 的隔离机制详解”">​</a></h3><p>理解隔离机制对于高效使用 Subagent 至关重要。</p><p><strong>上下文隔离</strong>：</p><ul><li>每个 Subagent 的上下文窗口从零开始（只有系统提示和你的子任务描述）</li><li>Subagent 不会&quot;看到&quot;你主会话中的对话历史</li><li>Subagent 不会&quot;看到&quot;主会话中已加载的文件内容</li><li>这意味着：<strong>你必须在子任务描述中提供足够的上下文信息</strong>，不能假设 Subagent &quot;知道&quot;什么</li></ul><p><strong>错误的子任务描述</strong>（假设 Subagent 已知上下文）：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&quot;重构这个文件&quot; ← Subagent 不知道是哪个文件、为什么重构</span></span></code></pre></div><p><strong>正确的子任务描述</strong>（自包含的上下文）：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&quot;重构 src/utils/format.ts 中的日期格式化函数。</span></span>\n<span class="line"><span> 当前问题：使用 moment.js（已废弃），需要迁移到 date-fns。</span></span>\n<span class="line"><span> 项目使用 TypeScript 严格模式，禁止使用 any。</span></span>\n<span class="line"><span> 完成后运行 pnpm test -- src/utils/__tests__/format.test.ts 验证。&quot;</span></span></code></pre></div><p><strong>文件系统共享</strong>：</p><ul><li>Subagent 和主会话操作的是<strong>同一个文件系统</strong></li><li>如果两个 Subagent 同时修改同一个文件，会产生冲突</li><li>因此：<strong>分发任务时必须确保文件集不重叠</strong></li></ul><p><strong>工具权限</strong>：</p><ul><li>Subagent 继承主会话的工具权限配置</li><li>如果主会话被允许执行 <code>git commit</code>，Subagent 也可以</li><li>对于高风险任务，考虑在子任务描述中加入&quot;只读操作&quot;的约束</li></ul><h3 id="subagent-的类型" tabindex="-1">Subagent 的类型 <a class="header-anchor" href="#subagent-的类型" aria-label="Permalink to “Subagent 的类型”">​</a></h3><p>Claude Code 支持多种专用 Subagent 类型：</p><table tabindex="0"><thead><tr><th>类型</th><th>用途</th><th>典型指令</th></tr></thead><tbody><tr><td><strong>Explore</strong></td><td>代码库探索和信息收集</td><td>&quot;用 Explore Agent 找出所有认证相关的代码&quot;</td></tr><tr><td><strong>Plan</strong></td><td>制定详细执行计划</td><td>&quot;用 Plan Agent 为这个重构任务制定分步计划&quot;</td></tr><tr><td><strong>General-purpose</strong></td><td>通用代码生成和修改（默认）</td><td>&quot;用 Subagent 重构 auth 模块&quot;</td></tr><tr><td><strong>Code Reviewer</strong></td><td>代码审查</td><td>&quot;用 Review Agent 审查 src/api/ 下的所有文件&quot;</td></tr></tbody></table><p>不同类型的 Subagent 拥有不同的系统提示和工具配置。Explore Agent 擅长搜索和导航但不擅长修改代码；Plan Agent 擅长分析和规划但不擅长执行。为任务选择正确的 Agent 类型是一步重要的效率优化。</p><h3 id="subagent-编排实战" tabindex="-1">Subagent 编排实战 <a class="header-anchor" href="#subagent-编排实战" aria-label="Permalink to “Subagent 编排实战”">​</a></h3><p>以下是一个完整的 Subagent 编排示例——为新项目搭建完整的基础设施：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>主会话指令：</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>&quot;我需要为新项目 &#39;TaskFlow&#39; 搭建基础设施。请使用 Subagent 并行执行以下任务：</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>Subagent 1（后端骨架）：</span></span>\n<span class="line"><span>  在当前目录创建 backend/ 子目录，初始化 Node.js + TypeScript 项目。</span></span>\n<span class="line"><span>  包含以下文件：</span></span>\n<span class="line"><span>  - backend/package.json（依赖：express, typescript, @types/express）</span></span>\n<span class="line"><span>  - backend/tsconfig.json（strict 模式，target ES2022）</span></span>\n<span class="line"><span>  - backend/src/index.ts（基础 Express 服务器，端口 3000）</span></span>\n<span class="line"><span>  - backend/src/routes/health.ts（/health 端点返回 { status: &#39;ok&#39; }）</span></span>\n<span class="line"><span>  - backend/.env.example（PORT=3000, NODE_ENV=development）</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>Subagent 2（前端骨架）：</span></span>\n<span class="line"><span>  在当前目录创建 frontend/ 子目录，使用 Vite + React + TypeScript。</span></span>\n<span class="line"><span>  包含以下文件：</span></span>\n<span class="line"><span>  - frontend/package.json（依赖：react, react-dom, vite, typescript）</span></span>\n<span class="line"><span>  - frontend/vite.config.ts（代理 /api 到 localhost:3000）</span></span>\n<span class="line"><span>  - frontend/src/App.tsx（基础页面，显示 &#39;TaskFlow&#39; 标题）</span></span>\n<span class="line"><span>  - frontend/src/main.tsx（ReactDOM 入口）</span></span>\n<span class="line"><span>  - frontend/index.html</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>Subagent 3（数据库和配置）：</span></span>\n<span class="line"><span>  在当前目录创建以下文件：</span></span>\n<span class="line"><span>  - docker-compose.yml（PostgreSQL 16 + Redis 7 服务）</span></span>\n<span class="line"><span>  - database/schema.sql（users 表和 tasks 表的建表语句）</span></span>\n<span class="line"><span>  - .gitignore（忽略 node_modules, dist, .env, *.log）</span></span>\n<span class="line"><span>  - README.md（项目简介、启动步骤、技术栈说明）</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>三个 Subagent 完成后，请检查各子目录的完整性，输出项目初始化报告。&quot;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>预期结果：3 个 Subagent 并行运行，约 2-3 分钟完成全部搭建。</span></span>\n<span class="line"><span>如果串行执行，至少需要 6-9 分钟。</span></span></code></pre></div><h3 id="subagent-的局限与应对" tabindex="-1">Subagent 的局限与应对 <a class="header-anchor" href="#subagent-的局限与应对" aria-label="Permalink to “Subagent 的局限与应对”">​</a></h3><p>了解 Subagent 能做什么，也要清楚它<strong>不能</strong>做什么：</p><table tabindex="0"><thead><tr><th>局限</th><th>说明</th><th>应对策略</th></tr></thead><tbody><tr><td><strong>不共享上下文</strong></td><td>Subagent 之间不能直接传递信息</td><td>由主会话在汇总阶段传递关键信息</td></tr><tr><td><strong>不能实时交互</strong></td><td>Subagent 执行期间不能向你提问</td><td>子任务描述必须足够清晰和自包含</td></tr><tr><td><strong>不能跨 Agent 锁定文件</strong></td><td>两个 Subagent 可能同时修改同一文件</td><td>严格检查文件集不重叠</td></tr><tr><td><strong>错误传播</strong></td><td>一个 Subagent 失败不影响其他，但你需要事后发现</td><td>主会话必须检查每个 Subagent 的返回状态</td></tr><tr><td><strong>费用叠加</strong></td><td>多个 Subagent 同时运行 = 多个 token 消耗并行发生</td><td>对于低成本任务（如单纯搜索），Flash 模型是更好的选择</td></tr></tbody></table><blockquote><p><strong>核心原则</strong>：Subagent 的价值 = 并行速度提升 - 上下文切换和汇总的成本。当并行任务超过 3 个，且每个任务需要 5 分钟以上的工作时，Subagent 的净收益最大。</p></blockquote><h2 id="_32-2-plan-模式驱动的分阶段开发" tabindex="-1">32.2 Plan 模式驱动的分阶段开发 <a class="header-anchor" href="#_32-2-plan-模式驱动的分阶段开发" aria-label="Permalink to “32.2 Plan 模式驱动的分阶段开发”">​</a></h2><p>如果说 Subagent 是在<strong>空间</strong>上并行化工作，那么 Plan 模式就是在<strong>时间</strong>上结构化工作。它把&quot;边想边做&quot;的即时响应模式，变成&quot;先谋后动、分步验证&quot;的工程化流程。</p><h3 id="plan-模式的核心理念" tabindex="-1">Plan 模式的核心理念 <a class="header-anchor" href="#plan-模式的核心理念" aria-label="Permalink to “Plan 模式的核心理念”">​</a></h3><p>在默认的交互模式中，你给 Claude Code 一个任务，它立刻开始执行。这对于简单任务是高效的——想得少、做得快。但对于复杂任务，这种模式有一个根本缺陷：<strong>在执行过程中才发现方向错误，前面的工作全部作废</strong>。</p><p>Plan 模式把这个流程颠倒过来：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>默认模式的流程：</span></span>\n<span class="line"><span>  需求 → 边想边做 → 发现问题 → 回退 → 重新做 → 可能再次发现问题 → ...</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>Plan 模式的流程：</span></span>\n<span class="line"><span>  需求 → 制定详细计划 → 你审核调整计划 → 分阶段执行 → 每阶段验证 → 完成</span></span></code></pre></div><p>核心区别在于：<strong>在动手写第一行代码之前，先对齐认知</strong>。</p><h3 id="plan-模式的三阶段流程" tabindex="-1">Plan 模式的三阶段流程 <a class="header-anchor" href="#plan-模式的三阶段流程" aria-label="Permalink to “Plan 模式的三阶段流程”">​</a></h3><p><strong>Phase 1：制定计划（Plan）</strong></p><p>当你给出一个复杂任务时，指令 Claude Code 进入 Plan 模式：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&quot;请用 Plan 模式为我设计以下功能的实现方案：</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>功能：为用户系统添加基于角色的权限控制（RBAC）</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>背景：</span></span>\n<span class="line"><span>- 当前用户系统基于 JWT 认证，用户表只有 role 字段（&#39;user&#39; | &#39;admin&#39;）</span></span>\n<span class="line"><span>- 需要扩展为：admin / manager / editor / viewer 四种角色</span></span>\n<span class="line"><span>- 每个角色有不同的 API 访问权限和数据可见范围</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>约束：</span></span>\n<span class="line"><span>- 不引入第三方权限库（如 CASL），保持依赖精简</span></span>\n<span class="line"><span>- 权限检查逻辑需要能单元测试</span></span>\n<span class="line"><span>- 数据库使用 PostgreSQL，已有 users 表</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>请输出详细的实现计划，包括：</span></span>\n<span class="line"><span>1. 数据模型变更（新的迁移文件）</span></span>\n<span class="line"><span>2. 权限定义和检查中间件的架构</span></span>\n<span class="line"><span>3. 各层（路由、服务、数据访问）的改动范围</span></span>\n<span class="line"><span>4. 测试策略</span></span>\n<span class="line"><span>5. 分步执行顺序&quot;</span></span></code></pre></div><p>Claude Code 会输出一份结构化的计划——不是代码，而是设计文档。这个阶段的关键在于<strong>你拥有审批权</strong>：审阅计划、提出修改、调整方向，直到计划符合你的期望。</p><p><strong>Phase 2：执行计划（Execute）</strong></p><p>计划确认后，进入执行阶段。关键原则：<strong>按计划的步骤顺序执行，每步完成后验证</strong>。</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&quot;计划已确认。现在请按计划执行。</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>第一步：创建数据库迁移文件（roles 表和 permissions 表）</span></span>\n<span class="line"><span>  - 文件：database/migrations/003_add_rbac.sql</span></span>\n<span class="line"><span>  - 完成后向我展示迁移内容并等待确认</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>第二步：实现权限定义模块</span></span>\n<span class="line"><span>  - 文件：src/auth/permissions.ts</span></span>\n<span class="line"><span>  - 定义角色-权限映射表</span></span>\n<span class="line"><span>  - 完成后运行单元测试验证</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>...逐步骤推进&quot;</span></span></code></pre></div><p>执行阶段的纪律：</p><ul><li><strong>一次只做一步</strong>：完成一步 → 验证 → 确认 → 下一步。不要&quot;一口气做完&quot;——那是 Plan 模式要避免的。</li><li><strong>每步都有验证</strong>：编译通过、测试通过、lint 通过。任何一步验证失败，停下来修，不要带着问题往前走。</li><li><strong>保持计划在视野内</strong>：如果执行中偏离了计划，暂停并更新计划，而不是悄悄偏离。</li></ul><p><strong>Phase 3：审查回顾（Review）</strong></p><p>全部步骤执行完毕后，做一次整体回顾：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&quot;实施完成。请对比最终实现和原始计划，输出差异报告：</span></span>\n<span class="line"><span>1. 哪些部分严格按计划执行了？</span></span>\n<span class="line"><span>2. 哪些部分在执行中做了调整？为什么？</span></span>\n<span class="line"><span>3. 有没有遗漏的需求？</span></span>\n<span class="line"><span>4. 代码质量评估（是否有需要重构的部分）？&quot;</span></span></code></pre></div><p>这个回顾的价值在于：让你（和人）从执行细节中抽离出来，回到&quot;战略&quot;层面看整个实现是否完整、是否合理。同时，这次回顾也是下次制定类似计划的参考资料。</p><h3 id="plan-模式实战-完整示例" tabindex="-1">Plan 模式实战：完整示例 <a class="header-anchor" href="#plan-模式实战-完整示例" aria-label="Permalink to “Plan 模式实战：完整示例”">​</a></h3><p>以下是一个完整的 Plan → Execute → Review 流程，以&quot;重构 API 错误处理&quot;为例。</p><p><strong>启动 Plan 模式</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&quot;请用 Plan 模式为以下任务制定实施方案：</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>任务：统一重构项目中所有 API 路由的错误处理</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>背景：</span></span>\n<span class="line"><span>- 项目有 23 个 API 路由文件，分布在 src/routes/ 下</span></span>\n<span class="line"><span>- 当前问题：错误处理不一致——有的返回 { error: string }，有的返回 { message: string }，</span></span>\n<span class="line"><span>  有的直接 throw（被全局兜底），有的在路由内 try-catch</span></span>\n<span class="line"><span>- HTTP 状态码使用也不一致：有的用 400 表示所有错误，有的用 500</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>目标：</span></span>\n<span class="line"><span>- 所有 API 返回统一的错误格式：{ error: { code: string, message: string, details?: any } }</span></span>\n<span class="line"><span>- HTTP 状态码遵循 REST 约定</span></span>\n<span class="line"><span>- 减少重复的 try-catch，使用统一的错误处理中间件</span></span>\n<span class="line"><span>- 不能引入运行时破坏性变更（向后兼容 30 天过渡期）</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>约束：</span></span>\n<span class="line"><span>- 不能引入新的第三方依赖</span></span>\n<span class="line"><span>- 现有的 47 个测试必须全部通过</span></span>\n<span class="line"><span>- 分阶段执行，避免一次改动超过 8 个文件&quot;</span></span></code></pre></div><p><strong>Claude Code 输出的计划示例</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>执行计划：统一 API 错误处理重构</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>Phase 1：基础设施（2 个文件）</span></span>\n<span class="line"><span>  1.1 创建 src/errors/AppError.ts —— 自定义错误类</span></span>\n<span class="line"><span>      - 包含 code, message, httpStatus, details 字段</span></span>\n<span class="line"><span>      - 预定义常用错误码（NOT_FOUND, VALIDATION_ERROR, UNAUTHORIZED 等）</span></span>\n<span class="line"><span>  1.2 创建 src/middleware/errorHandler.ts —— 统一错误处理中间件</span></span>\n<span class="line"><span>      - 捕获 AppError → 返回统一格式</span></span>\n<span class="line"><span>      - 捕获未知错误 → 返回 500 + 隐藏内部详情</span></span>\n<span class="line"><span>      - 记录错误日志</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>Phase 2：试点迁移（3-4 个路由文件）</span></span>\n<span class="line"><span>  2.1 选择最简单的 3 个路由（如 health.ts, ping.ts, version.ts）</span></span>\n<span class="line"><span>  2.2 移除路由内的 try-catch，改用 throw new AppError(...)</span></span>\n<span class="line"><span>  2.3 注册 errorHandler 中间件</span></span>\n<span class="line"><span>  2.4 更新相关测试，验证错误格式</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>Phase 3：逐批迁移（16 个路由文件）</span></span>\n<span class="line"><span>  3.1 按模块分组：用户模块（4 个文件）→ 订单模块（4 个文件）→ ...</span></span>\n<span class="line"><span>  3.2 每组迁移后运行完整测试套件</span></span>\n<span class="line"><span>  3.3 每组单独 Commit</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>Phase 4：兼容性过渡</span></span>\n<span class="line"><span>  4.1 在 errorHandler 中检测旧格式的请求头（X-API-Version）</span></span>\n<span class="line"><span>  4.2 对旧客户端返回旧格式（过渡期 30 天）</span></span>\n<span class="line"><span>  4.3 30 天后移除兼容代码</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>Phase 5：清理和文档</span></span>\n<span class="line"><span>  5.1 更新 API 文档中的错误格式说明</span></span>\n<span class="line"><span>  5.2 添加错误码对照表到项目 Wiki</span></span>\n<span class="line"><span>  5.3 移除不再需要的旧错误处理代码</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>估计总文件改动：25-30 个文件（含测试）</span></span>\n<span class="line"><span>建议执行时间：分 4 个对话会话，每会话 45-60 分钟</span></span></code></pre></div><p><strong>你审核后的调整</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&quot;计划总体可行。两点调整：</span></span>\n<span class="line"><span>1. Phase 2 试点增加到 5 个路由——health, ping, version 过于简单，</span></span>\n<span class="line"><span>   无法覆盖实际场景。加入 users/me.ts 和 posts/list.ts。</span></span>\n<span class="line"><span>2. 兼容过渡期改为 60 天——我们的客户端升级周期比较长。</span></span>\n<span class="line"><span>3. 在 Phase 1 增加一个步骤：先建一个错误码枚举文件 errors/codes.ts，</span></span>\n<span class="line"><span>   避免魔术字符串散布在各路由中。</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>调整后请确认最终计划。&quot;</span></span></code></pre></div><p>这就是 Plan 模式的核心价值：在代码被写出来之前，先用自然语言讨论清楚。这个讨论的成本（5-10 分钟）远远低于方向错误带来的返工成本（可能是数小时）。</p><h3 id="处理计划偏离" tabindex="-1">处理计划偏离 <a class="header-anchor" href="#处理计划偏离" aria-label="Permalink to “处理计划偏离”">​</a></h3><p>再好的计划，执行中也可能出现未预料到的情况。如何处理偏离是关键技能。</p><p><strong>场景：执行中发现依赖问题</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>原计划：</span></span>\n<span class="line"><span>  Phase 2 试点迁移 → 选择 users/me.ts 作为第一批</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>执行中发现：</span></span>\n<span class="line"><span>  users/me.ts 依赖一个未在计划中的工具函数 parseQuery()，</span></span>\n<span class="line"><span>  该函数的错误处理也需要统一</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>处理方式：</span></span>\n<span class="line"><span>  &quot;发现 users/me.ts 依赖 parseQuery()。</span></span>\n<span class="line"><span>   建议在 Phase 2 之前插入 Phase 2.5：</span></span>\n<span class="line"><span>   先重构 parseQuery() 的错误处理，再迁移 users/me.ts。</span></span>\n<span class="line"><span>   需要额外 15 分钟。是否批准？&quot;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>  ← 不要自己默默处理、偏离计划。让计划偏离可见、可控。</span></span></code></pre></div><p><strong>偏离处理原则</strong>：</p><table tabindex="0"><thead><tr><th>原则</th><th>做法</th></tr></thead><tbody><tr><td><strong>偏离可见化</strong></td><td>任何偏离计划的改动，先声明、后执行</td></tr><tr><td><strong>评估影响</strong></td><td>这个偏离会影响后续哪个步骤？是否需要调整计划？</td></tr><tr><td><strong>最小化偏离</strong></td><td>只做必需的调整，不要&quot;顺便&quot;扩展范围</td></tr><tr><td><strong>更新计划</strong></td><td>偏离确认后，更新计划文档（可以是对话中的简版）</td></tr></tbody></table><h3 id="plan-模式-vs-普通模式的决策框架" tabindex="-1">Plan 模式 vs 普通模式的决策框架 <a class="header-anchor" href="#plan-模式-vs-普通模式的决策框架" aria-label="Permalink to “Plan 模式 vs 普通模式的决策框架”">​</a></h3><table tabindex="0"><thead><tr><th>任务特征</th><th>推荐模式</th><th>理由</th></tr></thead><tbody><tr><td>改动 &lt; 3 个文件，逻辑简单</td><td>普通模式</td><td>Plan 的 overhead 不值得</td></tr><tr><td>改动 3-8 个文件，有明确的修改方向</td><td>普通模式</td><td>方向清晰，直接执行更快</td></tr><tr><td>改动 &gt; 8 个文件，或涉及架构变更</td><td><strong>Plan 模式</strong></td><td>需要先对齐方案，避免大范围返工</td></tr><tr><td>需求不够明确，需要探索</td><td><strong>Plan 模式</strong></td><td>用 Plan 来梳理需求，不是来执行</td></tr><tr><td>多人协作，需要评审</td><td><strong>Plan 模式</strong></td><td>Plan 文档是团队沟通的媒介</td></tr><tr><td>紧急 Bug 修复（范围明确）</td><td>普通模式</td><td>时间优先，Plan 环节会延误修复</td></tr></tbody></table><blockquote><p><strong>经验法则</strong>：当你犹豫&quot;要不要用 Plan 模式&quot;时，问自己一个问题——&quot;如果 Claude 第一版方案完全跑偏了，我有多难受？&quot; 难受程度越高，越应该用 Plan 模式。</p></blockquote><h2 id="_32-3-多会话并行工作" tabindex="-1">32.3 多会话并行工作 <a class="header-anchor" href="#_32-3-多会话并行工作" aria-label="Permalink to “32.3 多会话并行工作”">​</a></h2><p>第 31 章提到过多会话并行是效率优化的手段之一。这里我们从&quot;精通&quot;的角度深入展开——如何管理多个活跃会话、如何在会话间切换而不丢失上下文、以及如何与 Git Worktree 配合实现真正的并行开发。</p><h3 id="多会话的核心理念" tabindex="-1">多会话的核心理念 <a class="header-anchor" href="#多会话的核心理念" aria-label="Permalink to “多会话的核心理念”">​</a></h3><p>默认情况下，大多数人使用 Claude Code 的方式是&quot;一个会话做到完&quot;：打开 Claude Code → 做任务 A → 完成 → 关掉。这种方式的问题在于：你的大脑和项目状态都是有&quot;惯性&quot;的——当你被中断或需要切换到任务 B 时，你不得不丢弃任务 A 的上下文，然后重新加载任务 B 的上下文。来回切换的成本很高。</p><p>多会话并行的解决思路是：<strong>每个独立的开发线拥有自己的对话会话</strong>，你在这些会话之间切换，就像在 VSCode 的 Tab 之间切换一样——每个 Tab 保持各自的状态。</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>时间线视角：</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>单会话模式（串行）：</span></span>\n<span class="line"><span>  [任务 A ————————] [等待] [任务 B ————————] [等待] [任务 C ——]</span></span>\n<span class="line"><span>  ↑ 任务 A 的上下文在等待期间被浪费          ↑ 新任务需要重新加载上下文</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>多会话模式（并行推进）：</span></span>\n<span class="line"><span>  会话 1: [任务 A ——][暂停][—— 任务 A ——][暂停][—— 完成]</span></span>\n<span class="line"><span>  会话 2: [—— 任务 B ——————][暂停][—— 任务 B ——]</span></span>\n<span class="line"><span>  会话 3: [—————— 任务 C ———————————————— 完成]</span></span>\n<span class="line"><span>  </span></span>\n<span class="line"><span>  ↑ 每个会话保持各自的上下文连续性</span></span>\n<span class="line"><span>  ↑ 你在会话间切换，而不是丢弃和重建</span></span></code></pre></div><h3 id="典型的多会话应用场景" tabindex="-1">典型的多会话应用场景 <a class="header-anchor" href="#典型的多会话应用场景" aria-label="Permalink to “典型的多会话应用场景”">​</a></h3><p><strong>场景一：主线 + 支线</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>会话 1（主线）：Feature 开发 —— &quot;为博客系统添加评论功能&quot;</span></span>\n<span class="line"><span>  - 每天的主要工作时间在这里</span></span>\n<span class="line"><span>  - 保持连续的开发上下文</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>会话 2（支线）：Code Review —— &quot;审查 PR #234&quot;</span></span>\n<span class="line"><span>  - 同事的 PR 需要审查，但不能中断主线开发</span></span>\n<span class="line"><span>  - 切到会话 2，完成审查，切回会话 1 继续开发</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>会话 3（应急线）：Bug Fix —— &quot;生产环境登录超时 Bug&quot;</span></span>\n<span class="line"><span>  - 突发事件，需要立即处理</span></span>\n<span class="line"><span>  - 在会话 3 中和 Claude Code 一起排查和修复</span></span>\n<span class="line"><span>  - 修复完成后，切回会话 1，主线开发的上下文完好无损</span></span></code></pre></div><p><strong>场景二：并行功能开发（配合 Git Worktree）</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>会话 1（Worktree: feature/payment）：</span></span>\n<span class="line"><span>  开发支付模块 —— Claude Code 正在重构 PaymentService.ts</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>会话 2（Worktree: feature/notification）：</span></span>\n<span class="line"><span>  开发通知模块 —— Claude Code 正在实现 WebSocket 推送逻辑</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>会话 3（Worktree: feature/export）：</span></span>\n<span class="line"><span>  开发数据导出 —— Claude Code 正在写 CSV 生成和下载逻辑</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>三个会话可以同时进行，因为每个 Worktree 有独立的文件系统。</span></span>\n<span class="line"><span>你作为&quot;调度者&quot;，在三个会话之间分配注意力。</span></span></code></pre></div><p><strong>场景三：开发 + 学习 + 文档</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>会话 1：核心功能开发（高强度，每天 4-6 小时）</span></span>\n<span class="line"><span>会话 2：技术探索和学习（&quot;帮我理解 WebSocket 的心跳机制&quot;）</span></span>\n<span class="line"><span>会话 3：文档维护（&quot;更新 API 文档，补充新接口的参数说明&quot;）</span></span></code></pre></div><h3 id="会话管理实践" tabindex="-1">会话管理实践 <a class="header-anchor" href="#会话管理实践" aria-label="Permalink to “会话管理实践”">​</a></h3><p><strong>命名规范</strong></p><p>好的会话命名让你在 10 个并发会话中一眼找到目标：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>✅ 好的命名：</span></span>\n<span class="line"><span>  &quot;feat: 支付模块 - 微信支付&quot;</span></span>\n<span class="line"><span>  &quot;review: PR #234 - 用户认证重构&quot;</span></span>\n<span class="line"><span>  &quot;hotfix: 登录超时 #342&quot;</span></span>\n<span class="line"><span>  &quot;explore: WebSocket 重连策略&quot;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>❌ 坏的命名：</span></span>\n<span class="line"><span>  &quot;Session 1&quot;</span></span>\n<span class="line"><span>  &quot;Untitled&quot;</span></span>\n<span class="line"><span>  &quot;test&quot;</span></span>\n<span class="line"><span>  &quot;aaa&quot;</span></span></code></pre></div><p>命名建议：<code>类型: 模块/功能 - 具体内容</code>。类型包括 <code>feat</code>、<code>fix</code>、<code>review</code>、<code>explore</code>、<code>docs</code>、<code>refactor</code>。</p><p><strong>会话切换的最佳时机</strong></p><p>不要&quot;随机打断&quot;——在自然断点切换会话：</p><table tabindex="0"><thead><tr><th>自然断点</th><th>说明</th></tr></thead><tbody><tr><td>刚完成一个 Commit</td><td>工作得到了持久化，切走不会丢失</td></tr><tr><td>Claude Code 正在执行长时间操作</td><td>等待期间可以切到另一个会话做轻量任务</td></tr><tr><td>一个子任务刚验证通过</td><td>阶段性完成，心理上容易&quot;放下&quot;</td></tr><tr><td>遇到阻塞等待外部反馈</td><td>&quot;我发给同事 Review 了，等他回复&quot;</td></tr></tbody></table><p><strong>上下文的保持与恢复</strong></p><p>当你在会话 1 中暂停，切到会话 2 工作，再切回会话 1 时，Claude Code 的对话历史完整保留——不需要重新解释你在做什么。但为了更快恢复&quot;思维上下文&quot;，建议在暂停时让 Claude Code 做一个简短总结：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&quot;我马上要切到另一个会话处理紧急问题。请用 3-5 行总结当前进度：</span></span>\n<span class="line"><span>- 完成了什么？</span></span>\n<span class="line"><span>- 正在进行什么？</span></span>\n<span class="line"><span>- 下一步做什么？&quot;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>Claude Code 输出：</span></span>\n<span class="line"><span>&quot;&quot;&quot;</span></span>\n<span class="line"><span>当前进度摘要（feat: 支付模块）：</span></span>\n<span class="line"><span>✅ 已完成：PaymentService 核心逻辑、微信支付 API 对接</span></span>\n<span class="line"><span>🔄 正在进行：退款流程的错误处理（src/services/refund.ts 第 45 行）</span></span>\n<span class="line"><span>📋 下一步：补充退款流程的单元测试，然后提交 PR</span></span>\n<span class="line"><span>&quot;&quot;&quot;</span></span></code></pre></div><p>下次回到这个会话时，你会看到这个总结在对话末尾——10 秒内恢复思维上下文。</p><h3 id="vscode-多窗口配置" tabindex="-1">VSCode 多窗口配置 <a class="header-anchor" href="#vscode-多窗口配置" aria-label="Permalink to “VSCode 多窗口配置”">​</a></h3><p>如果你在 VSCode 中使用 Claude Code 扩展，多会话的最佳实践是多窗口配置：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>桌面布局建议（双显示器或大屏）：</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>┌─────────────────────────┬─────────────────────────┐</span></span>\n<span class="line"><span>│  显示器 1（主屏幕）       │  显示器 2（扩展屏）       │</span></span>\n<span class="line"><span>│                         │                         │</span></span>\n<span class="line"><span>│  VSCode 窗口 1          │  VSCode 窗口 2          │</span></span>\n<span class="line"><span>│  主开发分支              │  Review/Hotfix 分支     │</span></span>\n<span class="line"><span>│  Claude Code 会话 1     │  Claude Code 会话 2     │</span></span>\n<span class="line"><span>│                         │                         │</span></span>\n<span class="line"><span>│  ┌───────────────────┐  │  ┌───────────────────┐  │</span></span>\n<span class="line"><span>│  │ 代码编辑区         │  │  │ PR Diff 查看      │  │</span></span>\n<span class="line"><span>│  │ Claude Code 面板   │  │  │ Claude Code 面板   │  │</span></span>\n<span class="line"><span>│  └───────────────────┘  │  └───────────────────┘  │</span></span>\n<span class="line"><span>│                         │                         │</span></span>\n<span class="line"><span>├─────────────────────────┴─────────────────────────┤</span></span>\n<span class="line"><span>│  终端窗口（可选，第三个窗口）                        │</span></span>\n<span class="line"><span>│  - 监控 CI 状态                                     │</span></span>\n<span class="line"><span>│  - 运行定时任务                                      │</span></span>\n<span class="line"><span>└───────────────────────────────────────────────────┘</span></span></code></pre></div><p>多窗口 + 多会话的核心优势：<strong>物理空间上的隔离对应了逻辑上的隔离</strong>——你的大脑不会混淆&quot;左边窗口在做支付功能，右边窗口在审查 PR&quot;。</p><h3 id="多会话的注意事项" tabindex="-1">多会话的注意事项 <a class="header-anchor" href="#多会话的注意事项" aria-label="Permalink to “多会话的注意事项”">​</a></h3><table tabindex="0"><thead><tr><th>注意事项</th><th>说明</th></tr></thead><tbody><tr><td><strong>文件冲突</strong></td><td>如果两个会话操作相同的文件且不在不同 Worktree 中，后保存的会覆盖先保存的。务必确保并行的会话操作互不重叠的文件集，或者使用 Worktree 隔离</td></tr><tr><td><strong>Git 状态混乱</strong></td><td>同一目录下两个会话交替 commit/push 可能导致意外的 Git 状态。建议每个会话在开始前 <code>git status</code> 确认状态干净</td></tr><tr><td><strong>资源消耗</strong></td><td>每个活跃的 Claude Code 会话都消耗 API token。3 个并发会话 = 3 倍的 token 消耗速率。留意 API 账单</td></tr><tr><td><strong>注意力分散</strong></td><td>多会话是效率工具，但如果导致频繁切换（每 5 分钟换一次），效率反而下降。建议每个会话至少专注 30 分钟再切换</td></tr></tbody></table><h2 id="_32-4-git-worktree-隔离开发" tabindex="-1">32.4 Git Worktree 隔离开发 <a class="header-anchor" href="#_32-4-git-worktree-隔离开发" aria-label="Permalink to “32.4 Git Worktree 隔离开发”">​</a></h2><p>Git Worktree 是并行工作流的基石。第 31 章和第 22 章都提到过它，但这里我们要深入掌握它的全部使用模式——从基本操作到与 Claude Code 的深度集成。</p><h3 id="什么是-git-worktree" tabindex="-1">什么是 Git Worktree <a class="header-anchor" href="#什么是-git-worktree" aria-label="Permalink to “什么是 Git Worktree”">​</a></h3><p><code>git worktree</code> 让你在同一个 Git 仓库中创建多个独立的工作目录，每个目录可以在不同的分支上工作。这解决了&quot;我需要在 A 分支上开发，但突然需要切到 B 分支修 Bug，又不想 stash 或 commit 当前未完成的代码&quot;这个经典痛点。</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>传统方式（单工作目录）：</span></span>\n<span class="line"><span>  ~/project/  → 只有一个工作目录</span></span>\n<span class="line"><span>  切分支时：git stash → git switch → 做其他事 → git switch back → git stash pop</span></span>\n<span class="line"><span>  问题：stash 可能冲突，大型重构无法 stash，上下文被打断</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>Worktree 方式（多工作目录）：</span></span>\n<span class="line"><span>  ~/project/            → 主工作目录（main 或当前开发分支）</span></span>\n<span class="line"><span>  ~/project-hotfix/     → Hotfix 工作目录（hotfix/login-timeout 分支）</span></span>\n<span class="line"><span>  ~/project-feature-a/  → Feature A 工作目录（feature/payment 分支）</span></span>\n<span class="line"><span>  </span></span>\n<span class="line"><span>  每个目录有独立的文件系统状态和 Git 状态</span></span>\n<span class="line"><span>  共享同一个 .git 仓库（共享提交历史和分支）</span></span></code></pre></div><h3 id="基本操作" tabindex="-1">基本操作 <a class="header-anchor" href="#基本操作" aria-label="Permalink to “基本操作”">​</a></h3><p><strong>创建 Worktree</strong></p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 基于已有分支创建 Worktree</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> worktree</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ../project-hotfix</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hotfix/login-timeout</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 基于远程分支创建 Worktree</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> worktree</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ../project-feature-a</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origin/feature/payment</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 创建新分支并同时创建 Worktree</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> worktree</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -b</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature/new-module</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ../project-new-module</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 创建后，进入 Worktree 目录即可开始工作</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ../project-hotfix</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> branch</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 确认当前在 hotfix/login-timeout 分支</span></span></code></pre></div><p><strong>查看所有 Worktree</strong></p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> worktree</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 输出示例：</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># /Users/shibin/project             abc1234 [main]</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># /Users/shibin/project-hotfix      def5678 [hotfix/login-timeout]</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># /Users/shibin/project-feature-a   ghi9012 [feature/payment]</span></span></code></pre></div><p><strong>删除 Worktree</strong></p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 先删除 Worktree 注册，再删除目录</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> worktree</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> remove</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ../project-hotfix</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 如果 Worktree 中有未提交的更改，需要强制删除</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> worktree</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> remove</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --force</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ../project-hotfix</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 手动清理目录（如果 git worktree remove 没有删除目录）</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -rf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ../project-hotfix</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> worktree</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> prune</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 清理已不存在的 Worktree 引用</span></span></code></pre></div><h3 id="worktree-claude-code-的工作模式" tabindex="-1">Worktree + Claude Code 的工作模式 <a class="header-anchor" href="#worktree-claude-code-的工作模式" aria-label="Permalink to “Worktree + Claude Code 的工作模式”">​</a></h3><p>Worktree 为 Claude Code 提供了<strong>物理隔离</strong>——这是最安全的并行开发方式。以下是三种典型的组合模式：</p><p><strong>模式一：大功能隔离开发</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>场景：支付模块重构涉及 30+ 个文件，预计需要 2 天</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>步骤：</span></span>\n<span class="line"><span>1. git worktree add -b feature/payment-refactor ../project-payment main</span></span>\n<span class="line"><span>2. cd ../project-payment</span></span>\n<span class="line"><span>3. 启动 Claude Code，在新的 Worktree 中工作</span></span>\n<span class="line"><span>4. 完成重构 → git add + commit → git push</span></span>\n<span class="line"><span>5. 回到主目录创建 PR → merge</span></span>\n<span class="line"><span>6. git worktree remove ../project-payment</span></span>\n<span class="line"><span>7. git branch -d feature/payment-refactor  # 可选，清理本地分支</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>全程主目录（~/project/）保持干净——没有任何未提交的文件变更。</span></span>\n<span class="line"><span>如果重构期间需要紧急 Hotfix：切回主目录，正常操作，互不干扰。</span></span></code></pre></div><p><strong>模式二：并行功能开发</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>场景：同时推进三个独立的功能</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span># 创建三个 Worktree</span></span>\n<span class="line"><span>git worktree add -b feature/payment  ../project-payment main</span></span>\n<span class="line"><span>git worktree add -b feature/notification ../project-notification main</span></span>\n<span class="line"><span>git worktree add -b feature/export ../project-export main</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span># 在每个 Worktree 中启动独立的 Claude Code 会话</span></span>\n<span class="line"><span>cd ../project-payment    &amp;&amp; claude    # 会话 1：支付功能</span></span>\n<span class="line"><span>cd ../project-notification &amp;&amp; claude  # 会话 2：通知功能</span></span>\n<span class="line"><span>cd ../project-export     &amp;&amp; claude    # 会话 3：导出功能</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span># 你在三个会话之间分配时间</span></span>\n<span class="line"><span># 每个会话有独立的 Claude Code 对话历史和文件状态</span></span></code></pre></div><p><strong>模式三：实验性修改沙箱</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>场景：想尝试一个大重构方案，但不确定是否可行</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span># 创建实验 Worktree</span></span>\n<span class="line"><span>git worktree add -b experiment/radical-refactor ../project-experiment main</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span># 在实验 Worktree 中让 Claude Code 放手重构</span></span>\n<span class="line"><span># 不用担心破坏主项目</span></span>\n<span class="line"><span>cd ../project-experiment</span></span>\n<span class="line"><span>claude → &quot;请大规模重构 src/core/ 的数据流架构...&quot;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span># 实验结果：</span></span>\n<span class="line"><span># 成功 → 合并回 main</span></span>\n<span class="line"><span># 失败 → git worktree remove ../project-experiment + git branch -D experiment/radical-refactor</span></span>\n<span class="line"><span># 零成本尝试，零风险</span></span></code></pre></div><h3 id="worktree-中的-claude-code-配置" tabindex="-1">Worktree 中的 Claude Code 配置 <a class="header-anchor" href="#worktree-中的-claude-code-配置" aria-label="Permalink to “Worktree 中的 Claude Code 配置”">​</a></h3><p>每个 Worktree 是独立的文件系统，但共享 <code>.git</code> 目录。Claude Code 的项目配置（如 <code>.claude/</code> 目录中的 <code>settings.json</code>、<code>CLAUDE.md</code>）可能需要在 Worktree 之间保持一致或独立，取决于你的需求：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>场景 A：希望 Worktree 共享项目配置</span></span>\n<span class="line"><span>  → .claude/ 和 CLAUDE.md 已提交到 Git，Worktree 自然共享</span></span>\n<span class="line"><span>  → 在主目录更新 CLAUDE.md 后，在 Worktree 中 git pull 即可同步</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>场景 B：希望 Worktree 有独立的配置</span></span>\n<span class="line"><span>  → 在 Worktree 中修改 .claude/settings.local.json（此文件不提交到 Git）</span></span>\n<span class="line"><span>  → 或者在 Worktree 中本地覆盖 CLAUDE.md（不 commit）</span></span></code></pre></div><h3 id="何时用-worktree-何时用分支切换" tabindex="-1">何时用 Worktree，何时用分支切换 <a class="header-anchor" href="#何时用-worktree-何时用分支切换" aria-label="Permalink to “何时用 Worktree，何时用分支切换”">​</a></h3><table tabindex="0"><thead><tr><th>场景</th><th>推荐方式</th><th>理由</th></tr></thead><tbody><tr><td>两个任务改动的文件完全不重叠</td><td>普通分支切换</td><td>Worktree 的创建和维护有 overhead</td></tr><tr><td>两个任务可能改动重叠的文件</td><td><strong>Worktree</strong></td><td>避免 stash/commit 冲突</td></tr><tr><td>一个任务进行中（有未提交修改），另一个紧急任务来了</td><td><strong>Worktree</strong></td><td>不用 stash，不中断当前工作</td></tr><tr><td>大规模重构（持续数天）</td><td><strong>Worktree</strong></td><td>长时间保持工作区脏状态，不能用 stash</td></tr><tr><td>实验性修改（可能丢弃）</td><td><strong>Worktree</strong></td><td>失败后直接删除，主工作区零影响</td></tr><tr><td>简单的 Bug 修复（15 分钟完成）</td><td>普通分支切换</td><td>Worktree 的创建时间（10 秒）占任务比例太高</td></tr><tr><td>Code Review（只读，不修改代码）</td><td>普通分支切换或 GitHub PR 页面</td><td>不需要本地文件</td></tr></tbody></table><h3 id="worktree-的清理和维护" tabindex="-1">Worktree 的清理和维护 <a class="header-anchor" href="#worktree-的清理和维护" aria-label="Permalink to “Worktree 的清理和维护”">​</a></h3><p>随着时间推移，你可能积累大量废弃的 Worktree。定期清理是好习惯：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查看当前所有 Worktree</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> worktree</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 删除不需要的 Worktree</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> worktree</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> remove</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /path/to/stale-worktree</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 清理 Git 中已不存在的 Worktree 引用</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> worktree</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> prune</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 批量清理建议：每次发布完成后，清理该功能的 Worktree</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 保留主目录和当前活跃功能（最多 2-3 个）的 Worktree</span></span></code></pre></div><blockquote><p><strong>原则</strong>：Worktree 是工具，用完就收。不要保留 10 个已完成分支的 Worktree 目录——它们会占用磁盘空间，并让你的 <code>git worktree list</code> 变得难以阅读。</p></blockquote><h2 id="_32-5-定时任务与自动化-cron" tabindex="-1">32.5 定时任务与自动化（Cron） <a class="header-anchor" href="#_32-5-定时任务与自动化-cron" aria-label="Permalink to “32.5 定时任务与自动化（Cron）”">​</a></h2><p>Cron（定时任务）是 Claude Code 的一项独特能力：让你设置定期自动执行的任务，Claude Code 会在你设定的时间自动启动并执行指定的指令。这是&quot;让 AI 在你离开时继续工作&quot;的关键机制。</p><h3 id="cron-的核心理念" tabindex="-1">Cron 的核心理念 <a class="header-anchor" href="#cron-的核心理念" aria-label="Permalink to “Cron 的核心理念”">​</a></h3><p>Cron 改变了 Claude Code 的使用模式：从&quot;你主动发起&quot;变成&quot;系统自动触发&quot;。</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>传统模式：你来驱动</span></span>\n<span class="line"><span>  你坐在电脑前 → 打开 Claude Code → 下达指令 → 等待结果 → 审查</span></span>\n<span class="line"><span>  ↑ 你必须在场</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>Cron 模式：时间驱动</span></span>\n<span class="line"><span>  你设定规则 → 时间到了 → Claude Code 自动执行 → 结果在对话中等待你</span></span>\n<span class="line"><span>  ↑ 你不在场，工作仍然在推进</span></span></code></pre></div><p>这种模式最适合<strong>周期性检查任务</strong>——那些&quot;不做也没关系，但做了会很安心&quot;的重复性工作。</p><h3 id="cron-的使用场景" tabindex="-1">Cron 的使用场景 <a class="header-anchor" href="#cron-的使用场景" aria-label="Permalink to “Cron 的使用场景”">​</a></h3><p><strong>场景一：CI/CD 状态监控</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&quot;每 5 分钟检查一次 CI 状态，如果 main 分支的最新构建失败，分析失败原因并报告。&quot;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>Claude Code 的行为：</span></span>\n<span class="line"><span>  - 每 5 分钟自动运行一次</span></span>\n<span class="line"><span>  - 调用 gh 查看 CI 状态</span></span>\n<span class="line"><span>  - 如果构建失败，读取失败日志，分析根因</span></span>\n<span class="line"><span>  - 将分析结果留在对话中，你随时查看</span></span></code></pre></div><p><strong>场景二：代码审查提醒</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&quot;每天早上 9 点，检查是否有未审查的 PR，列出每个 PR 的标题、作者、文件变更数量。&quot;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>Claude Code 的行为：</span></span>\n<span class="line"><span>  - 每个工作日早上 9 点触发</span></span>\n<span class="line"><span>  - 拉取所有 open PR 的列表</span></span>\n<span class="line"><span>  - 筛选出等待你审查的 PR</span></span>\n<span class="line"><span>  - 生成审查优先级建议（根据变更规模和紧急性）</span></span></code></pre></div><p><strong>场景三：依赖更新检查</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&quot;每天早上 8 点，检查项目依赖是否有更新，如果有，列出更新内容和 Breaking Changes。&quot;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>Claude Code 的行为：</span></span>\n<span class="line"><span>  - 运行 pnpm outdated 或 npm outdated</span></span>\n<span class="line"><span>  - 对于有更新的包，查 CHANGELOG 或 release notes</span></span>\n<span class="line"><span>  - 标出有 Breaking Changes 的更新</span></span>\n<span class="line"><span>  - 建议升级优先级</span></span></code></pre></div><p><strong>场景四：每日代码变更摘要</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&quot;每天早上 9 点，生成昨日的代码变更摘要：</span></span>\n<span class="line"><span>- 列出昨天的所有 commit</span></span>\n<span class="line"><span>- 按模块分组</span></span>\n<span class="line"><span>- 统计新增/删除行数</span></span>\n<span class="line"><span>- 标出需要关注的大变更&quot;</span></span></code></pre></div><h3 id="cron-语法和使用方式" tabindex="-1">Cron 语法和使用方式 <a class="header-anchor" href="#cron-语法和使用方式" aria-label="Permalink to “Cron 语法和使用方式”">​</a></h3><p>在 Claude Code 中设置 Cron 任务，使用 <code>/cron</code> 命令或在对话中用自然语言描述：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>方式一：直接指令</span></span>\n<span class="line"><span>  &quot;请设置一个 Cron 任务：每天早上 9 点检查 CI 状态&quot;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>方式二：使用 /cron 命令</span></span>\n<span class="line"><span>  /cron add &quot;每 5 分钟检查 CI 状态&quot;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>方式三：标准 Cron 表达式</span></span>\n<span class="line"><span>  /cron add --schedule &quot;*/5 * * * *&quot; --prompt &quot;检查 CI 状态&quot;</span></span></code></pre></div><p>Cron 表达式标准格式（5 个字段）：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>┌──────────── 分钟 (0-59)</span></span>\n<span class="line"><span>│ ┌────────── 小时 (0-23)</span></span>\n<span class="line"><span>│ │ ┌──────── 日期 (1-31)</span></span>\n<span class="line"><span>│ │ │ ┌────── 月份 (1-12)</span></span>\n<span class="line"><span>│ │ │ │ ┌──── 星期 (0-6, 0=周日)</span></span>\n<span class="line"><span>│ │ │ │ │</span></span>\n<span class="line"><span>* * * * *</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>常用示例：</span></span>\n<span class="line"><span>  */5 * * * *     每 5 分钟</span></span>\n<span class="line"><span>  0 9 * * *       每天早上 9 点</span></span>\n<span class="line"><span>  0 9 * * 1-5     每个工作日早上 9 点</span></span>\n<span class="line"><span>  0 */2 * * *     每 2 小时</span></span>\n<span class="line"><span>  0 9 1 * *       每月 1 号早上 9 点</span></span>\n<span class="line"><span>  0 9,18 * * *    每天早上 9 点和下午 6 点</span></span></code></pre></div><h3 id="cron-任务的生命周期" tabindex="-1">Cron 任务的生命周期 <a class="header-anchor" href="#cron-任务的生命周期" aria-label="Permalink to “Cron 任务的生命周期”">​</a></h3><p><strong>创建</strong></p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 创建持久化 Cron 任务（保存到项目 .claude/settings.json）</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/cron</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;每天 9 点检查未审查的 PR&quot;</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 创建会话级 Cron 任务（仅当前会话有效）</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/cron</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --session</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;每 5 分钟检查 CI 状态&quot;</span></span></code></pre></div><p><strong>查看</strong></p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 列出所有 Cron 任务</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/cron</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 输出示例：</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ID       Schedule        Prompt                       Status</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># cron_1   */5 * * * *     检查 CI 状态                  active</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># cron_2   0 9 * * 1-5     检查未审查的 PR               active</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># cron_3   0 9 * * *       生成昨日代码变更摘要            paused</span></span></code></pre></div><p><strong>管理</strong></p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 暂停任务（保留配置，但不执行）</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/cron</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pause</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cron_2</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 恢复任务</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/cron</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> resume</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cron_2</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 删除任务</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/cron</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> remove</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cron_3</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查看任务执行历史</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/cron</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> history</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cron_1</span></span></code></pre></div><h3 id="持久化-vs-会话级任务" tabindex="-1">持久化 vs 会话级任务 <a class="header-anchor" href="#持久化-vs-会话级任务" aria-label="Permalink to “持久化 vs 会话级任务”">​</a></h3><table tabindex="0"><thead><tr><th>特性</th><th>持久化任务（Durable）</th><th>会话级任务（Session-only）</th></tr></thead><tbody><tr><td><strong>存储位置</strong></td><td>项目 <code>.claude/settings.json</code></td><td>仅当前会话内存</td></tr><tr><td><strong>生命周期</strong></td><td>跨会话持久存在，直到手动删除</td><td>当前会话结束时自动清除</td></tr><tr><td><strong>会话关闭后</strong></td><td>继续在后台执行（如果配置允许）</td><td>立即停止</td></tr><tr><td><strong>适用场景</strong></td><td>长期需要的定期检查（CI 监控、每日摘要）</td><td>临时需要的短期监控（今天下午反复检查部署状态）</td></tr><tr><td><strong>自动删除</strong></td><td>7 天无触发后自动停用（防止废弃任务积累）</td><td>会话结束时自动删除</td></tr></tbody></table><h3 id="自动删除机制" tabindex="-1">自动删除机制 <a class="header-anchor" href="#自动删除机制" aria-label="Permalink to “自动删除机制”">​</a></h3><p>为防止 Cron 任务无限制积累，Claude Code 对持久化 Cron 任务有自动停用机制：</p><ul><li>如果一个 Cron 任务<strong>连续 7 天</strong>没有被触发（因为会话关闭或设备离线），该任务会自动进入 <code>paused</code> 状态</li><li>你需要在 7 天内至少与 Claude Code 交互一次，让 Cron 有机会执行</li><li>你可以随时手动 <code>resume</code> 被自动暂停的任务</li></ul><p>这一机制确保你不会在三个月后发现有 47 个 Cron 任务在后台空转。</p><h3 id="cron-实战示例" tabindex="-1">Cron 实战示例 <a class="header-anchor" href="#cron-实战示例" aria-label="Permalink to “Cron 实战示例”">​</a></h3><p><strong>示例一：CI 监控 + 自动分析</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&quot;请设置一个 Cron 任务：</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>调度：每 10 分钟检查一次</span></span>\n<span class="line"><span>指令：检查 GitHub Actions 中 main 分支的最新 workflow run 状态。</span></span>\n<span class="line"><span>      如果失败：</span></span>\n<span class="line"><span>      1. 获取失败日志</span></span>\n<span class="line"><span>      2. 分析失败原因（编译错误 / 测试失败 / 环境问题）</span></span>\n<span class="line"><span>      3. 如果能在 5 分钟内修复，直接创建 fix PR</span></span>\n<span class="line"><span>      4. 如果不能自动修复，生成详细的分析报告</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>任务名称：CI Monitor - Main Branch</span></span>\n<span class="line"><span>类型：持久化&quot;</span></span></code></pre></div><p><strong>示例二：每日技术资讯摘要</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&quot;请设置一个 Cron 任务：</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>调度：每天早上 8:30</span></span>\n<span class="line"><span>指令：检查以下技术动态（仅本项目相关的技术栈）：</span></span>\n<span class="line"><span>      1. React / TypeScript / Node.js 的最新版本和重要更新</span></span>\n<span class="line"><span>      2. 本项目 package.json 中依赖的安全公告</span></span>\n<span class="line"><span>      3. GitHub Trending 中与项目技术栈相关的新项目</span></span>\n<span class="line"><span>      将所有信息汇总为简洁的&#39;每日技术简报&#39;，优先级排序。</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>任务名称：Daily Tech Brief</span></span>\n<span class="line"><span>类型：持久化&quot;</span></span></code></pre></div><p><strong>示例三：会话期间的临时监控</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&quot;请设置一个会话级 Cron 任务：</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>调度：每 2 分钟检查一次</span></span>\n<span class="line"><span>指令：检查本次部署的日志输出文件 /tmp/deploy-output.log，</span></span>\n<span class="line"><span>      如果出现 &#39;Deploy completed successfully&#39; 就通知我，</span></span>\n<span class="line"><span>      如果出现 &#39;Deploy failed&#39; 就立刻提醒我查看错误。</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>任务名称：Deploy Monitor（临时）</span></span>\n<span class="line"><span>类型：会话级（部署完成后就删除）&quot;</span></span></code></pre></div><h3 id="cron-使用的最佳实践" tabindex="-1">Cron 使用的最佳实践 <a class="header-anchor" href="#cron-使用的最佳实践" aria-label="Permalink to “Cron 使用的最佳实践”">​</a></h3><ol><li><p><strong>不要过度使用</strong>：Cron 任务会消耗 API token。一个每 5 分钟运行的 Cron 任务 = 每天 288 次 API 调用。确保每次调用的价值大于其成本。</p></li><li><p><strong>优先用会话级任务做试验</strong>：不确定一个 Cron 任务是否有用时，先用 <code>--session</code> 创建会话级任务试用一天。如果确实有用，再升级为持久化任务。</p></li><li><p><strong>给每个任务清晰的名称和用途描述</strong>：一个月后回看 <code>/cron list</code> 时，你还能记得每个任务是做什么的。</p></li><li><p><strong>定期审查</strong>：每月做一次 Cron 任务清理——删除不再需要的，暂停暂时不需要的，保留真正有价值的。</p></li><li><p><strong>注意时区</strong>：Cron 任务默认使用 UTC 时间。如果需要本地时间，在指令中明确说明（如 &quot;每天早上 9 点（北京时间）&quot;）。</p></li></ol><h2 id="_32-6-workflow-编排" tabindex="-1">32.6 Workflow 编排 <a class="header-anchor" href="#_32-6-workflow-编排" aria-label="Permalink to “32.6 Workflow 编排”">​</a></h2><p>Workflow 是 Claude Code 高级能力中的&quot;终极武器&quot;——它把前面几节介绍的 Subagent、Plan 模式、Cron 等能力组合成一个可编排的多阶段流水线。如果说单个 Subagent 是一个工人，Workflow 就是一整条生产线。</p><h3 id="什么是-workflow" tabindex="-1">什么是 Workflow <a class="header-anchor" href="#什么是-workflow" aria-label="Permalink to “什么是 Workflow”">​</a></h3><p>Workflow 是一个<strong>预定义的、多 Agent 协作的执行脚本</strong>，它定义了多个 Agent 如何分工、如何通信、如何汇总结果。Workflow 的执行由 Claude Code 自动编排，你只需要定义规则和检查点。</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Workflow = 多个 Agent + 编排规则 + 质量门禁 + 结果汇总</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>┌─────────────────────────────────────────────────────────┐</span></span>\n<span class="line"><span>│                    Workflow: 发布前审查                    │</span></span>\n<span class="line"><span>│                                                         │</span></span>\n<span class="line"><span>│  Phase 1: 并行审查                                       │</span></span>\n<span class="line"><span>│  ┌──────────┐  ┌──────────┐  ┌──────────┐              │</span></span>\n<span class="line"><span>│  │ Agent A  │  │ Agent B  │  │ Agent C  │              │</span></span>\n<span class="line"><span>│  │ 安全审查  │  │ 性能审查  │  │ 代码风格  │              │</span></span>\n<span class="line"><span>│  └────┬─────┘  └────┬─────┘  └────┬─────┘              │</span></span>\n<span class="line"><span>│       │              │              │                    │</span></span>\n<span class="line"><span>│       └──────────────┴──────────────┘                    │</span></span>\n<span class="line"><span>│                      │                                   │</span></span>\n<span class="line"><span>│  Phase 2: 汇总分析（主 Agent）                            │</span></span>\n<span class="line"><span>│  ┌──────────────────────────────────────┐               │</span></span>\n<span class="line"><span>│  │ 合并三个审查结果                       │               │</span></span>\n<span class="line"><span>│  │ 去重（同一个问题可能被多人发现）         │               │</span></span>\n<span class="line"><span>│  │ 按严重程度排序                         │               │</span></span>\n<span class="line"><span>│  │ 生成可操作的修复建议                    │               │</span></span>\n<span class="line"><span>│  └──────────────────────────────────────┘               │</span></span>\n<span class="line"><span>│                      │                                   │</span></span>\n<span class="line"><span>│  Phase 3: 修复验证（可选）                                │</span></span>\n<span class="line"><span>│  ┌──────────────────────────────────────┐               │</span></span>\n<span class="line"><span>│  │ 针对发现的问题，逐个修复                │               │</span></span>\n<span class="line"><span>│  │ 每个修复后重新运行相关测试              │               │</span></span>\n<span class="line"><span>│  │ 生成修复报告                           │               │</span></span>\n<span class="line"><span>│  └──────────────────────────────────────┘               │</span></span>\n<span class="line"><span>└─────────────────────────────────────────────────────────┘</span></span></code></pre></div><h3 id="workflow-的适用场景" tabindex="-1">Workflow 的适用场景 <a class="header-anchor" href="#workflow-的适用场景" aria-label="Permalink to “Workflow 的适用场景”">​</a></h3><p>Workflow 不是日常使用的工具——它的设置成本较高，适合以下场景：</p><table tabindex="0"><thead><tr><th>场景</th><th>为什么用 Workflow</th><th>预期收益</th></tr></thead><tbody><tr><td><strong>全面代码审查</strong></td><td>单次 Code Review 容易遗漏。多 Agent 从不同角度独立审查，然后交叉验证</td><td>发现 3-5 倍于单次审查的问题</td></tr><tr><td><strong>大规模迁移</strong></td><td>迁移涉及数百个文件，需要分阶段、分模块、自动验证</td><td>数天的工作量压缩到数小时</td></tr><tr><td><strong>安全审计</strong></td><td>需要多个独立视角：代码静态分析、依赖漏洞扫描、数据流追踪、OWASP 合规</td><td>覆盖手动审计难以穷举的攻击面</td></tr><tr><td><strong>知识库构建</strong></td><td>需要从整个代码库中提取特定信息，汇总成结构化文档</td><td>将数周的文档编写工作压缩到数小时</td></tr><tr><td><strong>重构前影响分析</strong></td><td>改一个核心模块前，需要全面评估影响范围</td><td>避免&quot;改了 A 发现 B 崩了&quot;的连锁反应</td></tr></tbody></table><h3 id="workflow-的编排模式" tabindex="-1">Workflow 的编排模式 <a class="header-anchor" href="#workflow-的编排模式" aria-label="Permalink to “Workflow 的编排模式”">​</a></h3><p><strong>模式一：流水线（Pipeline）</strong></p><p>Agent 按顺序执行，前一个的输出是后一个的输入。</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Pipeline: 代码生成 → 测试 → 审查 → 修复 → 文档更新</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>Agent 1: 生成代码    ──→ 输出：src/newFeature.ts</span></span>\n<span class="line"><span>Agent 2: 编写测试    ──→ 输出：src/__tests__/newFeature.test.ts</span></span>\n<span class="line"><span>Agent 3: 审查代码    ──→ 输出：review-issues.md</span></span>\n<span class="line"><span>Agent 4: 修复问题    ──→ 输出：更新后的 src/newFeature.ts</span></span>\n<span class="line"><span>Agent 5: 更新文档    ──→ 输出：docs/newFeature.md</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>适用场景：有明确前后依赖关系的任务链</span></span>\n<span class="line"><span>优势：每步都可以设置质量门禁（测试不通过 → 不进入下一步）</span></span>\n<span class="line"><span>劣势：总时间 = 所有步骤时间之和（无并行加速）</span></span></code></pre></div><p><strong>模式二：并行 + 汇总（Fan-out / Fan-in）</strong></p><p>多个 Agent 同时处理不同部分，然后汇总。</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Fan-out + Fan-in: 并行代码审查</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>         ┌──→ Agent 1: 审查安全性 ──┐</span></span>\n<span class="line"><span>         │                           │</span></span>\n<span class="line"><span>主 Agent ──→ Agent 2: 审查性能    ──┼──→ 汇总 Agent: 合并结果</span></span>\n<span class="line"><span>         │                           │</span></span>\n<span class="line"><span>         └──→ Agent 3: 审查可维护性 ──┘</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>适用场景：同一任务需要多角度分析，各角度互不依赖</span></span>\n<span class="line"><span>优势：并行执行，总时间 = 最慢 Agent 的时间</span></span>\n<span class="line"><span>劣势：可能产生重复发现，需要汇总去重</span></span></code></pre></div><p><strong>模式三：循环直到满足（Loop-until）</strong></p><p>Agent 反复执行一个操作，直到满足终止条件。</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Loop-until: 找 Bug 直到干净</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>初始化：Bug 计数 = 0</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>循环：</span></span>\n<span class="line"><span>  Agent: 扫描代码 → 发现 Bug？ → 是 → 修复 → Bug 计数++ → 继续循环</span></span>\n<span class="line"><span>                                → 否 → 终止</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>终止条件：连续 3 次扫描没有发现新 Bug</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>适用场景：质量驱动的迭代优化（Bug 修复、性能优化、代码清理）</span></span>\n<span class="line"><span>优势：不留遗漏，直到真正&quot;干净&quot;</span></span>\n<span class="line"><span>劣势：Agent 可能反复修复同一个位置的不同问题，效率较低</span></span></code></pre></div><p><strong>模式四：对抗验证（Adversarial Verification）</strong></p><p>多个 Agent 从对立角度验证同一个结果。</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Adversarial: 安全审计</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>Agent A（攻击者视角）：&quot;假设我是攻击者，如何绕过这段代码的安全检查？&quot;</span></span>\n<span class="line"><span>Agent B（防御者视角）：&quot;假设我是安全专家，这段代码有哪些防护不足？&quot;</span></span>\n<span class="line"><span>Agent C（独立审计）：&quot;独立审查，不预设攻击或防御立场&quot;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>汇总 Agent：三个 Agent 的发现对比 → 共同发现 = 高可信度 / 独立发现 = 值得关注</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>适用场景：安全审计、关键业务逻辑验证、合规检查</span></span>\n<span class="line"><span>优势：对抗视角更容易发现隐蔽问题</span></span>\n<span class="line"><span>劣势：对 token 消耗较大（多个 Agent 的深度分析）</span></span></code></pre></div><h3 id="workflow-中的-token-预算管理" tabindex="-1">Workflow 中的 Token 预算管理 <a class="header-anchor" href="#workflow-中的-token-预算管理" aria-label="Permalink to “Workflow 中的 Token 预算管理”">​</a></h3><p>Workflow 涉及多个 Agent，每个 Agent 都消耗 token。不加控制的 Workflow 可能一次消耗数十万甚至上百万 token。管理策略：</p><p><strong>预算层次</strong>：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Workflow 总预算：200,000 tokens（根据任务复杂度调整）</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>分配：</span></span>\n<span class="line"><span>  - Phase 1（并行审查）：3 个 Agent × 40,000 tokens = 120,000 tokens</span></span>\n<span class="line"><span>  - Phase 2（汇总分析）：1 个 Agent × 40,000 tokens = 40,000 tokens</span></span>\n<span class="line"><span>  - Phase 3（修复验证）：1-2 个 Agent × 20,000 tokens = 40,000 tokens</span></span></code></pre></div><p><strong>成本控制原则</strong>：</p><table tabindex="0"><thead><tr><th>原则</th><th>做法</th></tr></thead><tbody><tr><td><strong>重要任务用大模型</strong></td><td>最终汇总和关键决策用 V4 Pro / Opus</td></tr><tr><td><strong>机械任务用小模型</strong></td><td>代码扫描、格式检查用 V4 Flash</td></tr><tr><td><strong>设置停止条件</strong></td><td>&quot;如果连续 5 次扫描都没有发现新问题，终止 Workflow&quot;</td></tr><tr><td><strong>对有价值的结果才深度分析</strong></td><td>先用低成本 Agent 快速扫描，只对标记为&quot;可能有问题&quot;的区域进行深度分析</td></tr><tr><td><strong>分批执行</strong></td><td>不需要一个 Workflow 做完所有事。分 2-3 个 Workflow 执行，中间你审核输出</td></tr></tbody></table><h3 id="定义-workflow-的方式" tabindex="-1">定义 Workflow 的方式 <a class="header-anchor" href="#定义-workflow-的方式" aria-label="Permalink to “定义 Workflow 的方式”">​</a></h3><p>在 Claude Code 中，你可以通过对话直接定义 Workflow：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&quot;请按以下 Workflow 执行代码审查：</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>Phase 1（并行）：</span></span>\n<span class="line"><span>  启动 3 个 Subagent，分别是：</span></span>\n<span class="line"><span>  - Security Agent：从 OWASP Top 10 角度审查 src/api/ 下所有路由文件</span></span>\n<span class="line"><span>  - Performance Agent：识别 src/api/ 下可能的性能瓶颈（N+1 查询、缺少缓存、同步阻塞）</span></span>\n<span class="line"><span>  - Maintainability Agent：评估代码可维护性（函数复杂度、重复代码、命名质量）</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>Phase 2（汇总）：</span></span>\n<span class="line"><span>  收集 3 个 Agent 的审查结果，生成统一的审查报告：</span></span>\n<span class="line"><span>  - 按严重程度排序（Critical / High / Medium / Low）</span></span>\n<span class="line"><span>  - 合并重复发现</span></span>\n<span class="line"><span>  - 为每个问题提供修复建议</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>Phase 3（修复）：</span></span>\n<span class="line"><span>  对 Critical 和 High 级别的问题，逐个修复。</span></span>\n<span class="line"><span>  修复后运行测试验证。</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>Token 预算：总计不超过 150,000 tokens。</span></span>\n<span class="line"><span>模型策略：Phase 1 使用 V4 Flash，Phase 2 和 Phase 3 使用 V4 Pro。</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>完成后生成审查报告文件：docs/code-review-$(date).md&quot;</span></span></code></pre></div><h3 id="workflow-实战-大规模-api-迁移" tabindex="-1">Workflow 实战：大规模 API 迁移 <a class="header-anchor" href="#workflow-实战-大规模-api-迁移" aria-label="Permalink to “Workflow 实战：大规模 API 迁移”">​</a></h3><p>以下是一个完整的 Workflow 实战案例——将 REST API 迁移到 GraphQL：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Workflow: REST → GraphQL 迁移（预估 4-6 小时）</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>Phase 1: 分析（并行，约 30 分钟）</span></span>\n<span class="line"><span>  Agent 1: 分析所有 REST 端点的输入输出结构</span></span>\n<span class="line"><span>    → 扫描 src/routes/ 下 47 个路由文件</span></span>\n<span class="line"><span>    → 提取每个端点的请求参数和响应结构</span></span>\n<span class="line"><span>    → 输出：rest-endpoints.json（结构化数据）</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>  Agent 2: 分析前端对 API 的调用模式</span></span>\n<span class="line"><span>    → 扫描 src/pages/ 和 src/components/ 下的 API 调用</span></span>\n<span class="line"><span>    → 统计每个端点的调用频率和使用的字段</span></span>\n<span class="line"><span>    → 输出：api-usage.json（调用模式分析）</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>  Agent 3: 评估迁移风险</span></span>\n<span class="line"><span>    → 分析哪些端点有复杂业务逻辑（不适合简单映射到 GraphQL）</span></span>\n<span class="line"><span>    → 识别破坏性变更的 API（参数变更、响应结构变更）</span></span>\n<span class="line"><span>    → 输出：migration-risks.md（风险评估报告）</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>Phase 2: 设计（串行，约 1 小时）</span></span>\n<span class="line"><span>  Agent 4（V4 Pro）: 基于 Phase 1 的三个输出，设计 GraphQL Schema</span></span>\n<span class="line"><span>    → 定义 Query、Mutation、Type 结构</span></span>\n<span class="line"><span>    → 优先覆盖高频调用的端点</span></span>\n<span class="line"><span>    → 输出：schema.graphql + schema-design.md</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>  你审核 Schema → 调整 → 确认</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>Phase 3: 实现（并行，约 2 小时）</span></span>\n<span class="line"><span>  将 Schema 按业务领域拆分，并行实现：</span></span>\n<span class="line"><span>  Agent 5: User 领域的 GraphQL Resolver（8 个端点 → 5 个 Query + 3 个 Mutation）</span></span>\n<span class="line"><span>  Agent 6: Order 领域的 GraphQL Resolver（12 个端点 → 6 个 Query + 4 个 Mutation）</span></span>\n<span class="line"><span>  Agent 7: Product 领域的 GraphQL Resolver（7 个端点 → 4 个 Query + 2 个 Mutation）</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>Phase 4: 测试和验证（串行，约 1 小时）</span></span>\n<span class="line"><span>  Agent 8: 为 GraphQL Resolver 编写集成测试</span></span>\n<span class="line"><span>  Agent 9: 更新前端 API 调用（切换到 GraphQL）</span></span>\n<span class="line"><span>  运行完整测试套件 → 验证通过</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>Phase 5: 文档和清理（约 30 分钟）</span></span>\n<span class="line"><span>  Agent 10: 生成 GraphQL API 文档</span></span>\n<span class="line"><span>  Agent 11: 标记废弃的 REST 端点，添加迁移提示</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>总 token 预估：250,000 - 400,000 tokens</span></span>\n<span class="line"><span>总时间预估：4-6 小时（对比手动迁移需要 3-5 天）</span></span></code></pre></div><h3 id="workflow-的调试和监控" tabindex="-1">Workflow 的调试和监控 <a class="header-anchor" href="#workflow-的调试和监控" aria-label="Permalink to “Workflow 的调试和监控”">​</a></h3><p>Workflow 执行过程中可能出现各种问题。以下是调试策略：</p><p><strong>常见问题和应对</strong>：</p><table tabindex="0"><thead><tr><th>问题</th><th>症状</th><th>应对</th></tr></thead><tbody><tr><td><strong>Agent 产出质量差</strong></td><td>审查结果泛泛而谈，没有具体代码引用</td><td>收紧 Agent 指令——要求&quot;每发现一个问题必须引用具体的文件名和行号&quot;</td></tr><tr><td><strong>并行 Agent 产出重复</strong></td><td>三个 Agent 发现了相同的问题</td><td>在汇总阶段增加去重逻辑；或调整各 Agent 的审查范围，减少重叠</td></tr><tr><td><strong>Agent 超时或卡住</strong></td><td>某个 Agent 执行超过预期时间的 2 倍</td><td>设置超时机制——&quot;如果单个 Agent 超过 10 分钟无输出，跳过并标记为未完成&quot;</td></tr><tr><td><strong>汇总阶段信息过载</strong></td><td>汇总 Agent 收到太多信息，遗漏重要发现</td><td>要求各 Agent 在输出前先做一次自过滤——&quot;只输出 Critical 和 High 级别的问题&quot;</td></tr><tr><td><strong>Token 超支</strong></td><td>总消耗超出预算 50% 以上</td><td>在 Workflow 中设置硬性 Token 上限，达到上限时终止并输出已完成部分的报告</td></tr></tbody></table><p><strong>监控清单</strong>：</p><p>Workflow 执行期间，定期检查：</p><ul><li>[ ] 当前哪个 Phase 在执行？进度百分比？</li><li>[ ] 各 Agent 的状态（运行中 / 完成 / 失败）？</li><li>[ ] Token 消耗是否在预算内？</li><li>[ ] 有没有 Agent 的输出明显不符合预期（需要提前终止）？</li></ul><blockquote><p><strong>核心原则</strong>：Workflow 是自动化的，但自动化不等于&quot;不用管&quot;。你需要像指挥一个团队一样监控 Workflow 的执行——及时发现偏离、做出调整、在必要时终止或重试。</p></blockquote><h2 id="_32-7-本章小结" tabindex="-1">32.7 本章小结 <a class="header-anchor" href="#_32-7-本章小结" aria-label="Permalink to “32.7 本章小结”">​</a></h2><p>本章是第七篇&quot;精通篇&quot;的第一章，介绍了六种 Claude Code 高级工作流。这六种能力构成了从&quot;一个人 + 一个 AI 助手&quot;进化到&quot;一个人 + 一个 AI 团队&quot;的完整工具集：</p><ol><li><p><strong>Subagent 多 Agent 协作</strong>：将独立子任务分发给多个 Subagent 并行执行，利用上下文隔离和并行加速，实现&quot;一人同时推进多个方向&quot;。适用条件：子任务互不依赖、文件集不重叠、每个子任务描述自包含。</p></li><li><p><strong>Plan 模式分阶段开发</strong>：将&quot;边想边做&quot;改为&quot;先谋后动&quot;的工程化流程——Phase 1 制定计划并审核、Phase 2 按计划分步执行并逐步验证、Phase 3 整体回顾对比。核心价值在于：在写代码之前对齐认知，避免方向错误导致的大规模返工。</p></li><li><p><strong>多会话并行工作</strong>：每个独立的开发线拥有自己的会话，保持上下文连续性。典型场景包括主线+支线+应急线、并行功能开发、开发+学习+文档。关键纪律：命名规范、在自然断点切换、使用进度摘要快速恢复上下文。</p></li><li><p><strong>Git Worktree 隔离开发</strong>：在同一个仓库中创建多个独立工作目录，实现物理级别的文件系统隔离。特别适用于大功能开发（持续数天不改动主目录）、并行功能开发（每个功能独立 Worktree）、实验性修改沙箱（失败零成本丢弃）。</p></li><li><p><strong>Cron 定时任务自动化</strong>：让 Claude Code 按时间表自动执行周期性任务，实现&quot;你不在场时工作仍在推进&quot;。适用于 CI 监控、每日代码审查提醒、依赖更新检查、每日变更摘要等场景。关键纪律：不过度使用（每次调用都有价值）、定期清理废弃任务。</p></li><li><p><strong>Workflow 编排</strong>：将 Subagent、Plan 模式等能力组合成多 Agent 协作流水线。四种编排模式（流水线、并行汇总、循环直到满足、对抗验证）覆盖了从代码审查到大规模迁移的各种复杂场景。核心挑战是 Token 预算管理和执行监控。</p></li></ol><h3 id="六种工作流的联系与选择" tabindex="-1">六种工作流的联系与选择 <a class="header-anchor" href="#六种工作流的联系与选择" aria-label="Permalink to “六种工作流的联系与选择”">​</a></h3><p>这六种能力不是独立的，而是层层叠加、可以组合使用：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>你的工作流工具箱：</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>  日常开发：</span></span>\n<span class="line"><span>    普通模式（小任务）+ Plan 模式（复杂任务）</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>  并行加速：</span></span>\n<span class="line"><span>    + Subagent（独立子任务并行）</span></span>\n<span class="line"><span>    + 多会话（多开发线独立推进）</span></span>\n<span class="line"><span>    + Git Worktree（需要文件系统隔离时）</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>  自动化：</span></span>\n<span class="line"><span>    + Cron（周期性任务自动触发）</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>  复杂编排：</span></span>\n<span class="line"><span>    + Workflow（多 Agent 协作流水线）</span></span></code></pre></div><p>选择工作流的决策树：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>你的任务特征是什么？</span></span>\n<span class="line"><span>  │</span></span>\n<span class="line"><span>  ├── 单文件、逻辑简单 → 普通模式，直接执行</span></span>\n<span class="line"><span>  │</span></span>\n<span class="line"><span>  ├── 多文件、有依赖顺序 → Plan 模式，分阶段推进</span></span>\n<span class="line"><span>  │</span></span>\n<span class="line"><span>  ├── 多个独立子任务 → Subagent 并行分发</span></span>\n<span class="line"><span>  │</span></span>\n<span class="line"><span>  ├── 多个开发线（不同功能/Bug/Review）→ 多会话并行</span></span>\n<span class="line"><span>  │   └── 需要修改同一批文件？→ 加上 Git Worktree 隔离</span></span>\n<span class="line"><span>  │</span></span>\n<span class="line"><span>  ├── 需要周期性自动执行 → Cron 定时任务</span></span>\n<span class="line"><span>  │</span></span>\n<span class="line"><span>  └── 端到端的复杂流程（审查/迁移/审计）</span></span>\n<span class="line"><span>      → Workflow 编排（组合 Subagent + Plan 模式）</span></span></code></pre></div><h3 id="从精通到创造" tabindex="-1">从精通到创造 <a class="header-anchor" href="#从精通到创造" aria-label="Permalink to “从精通到创造”">​</a></h3><p>高级工作流的最终目标不是&quot;用更多的功能&quot;，而是<strong>建立你自己的高效工作模式</strong>。这六种能力是积木，你可以根据自己的项目特点、团队规模、个人偏好，组合出最适合你的工作流体系。</p><p>一个成熟的 Claude Code 精通用户的典型一天：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>08:30 - Cron 自动生成昨日代码变更摘要，你在手机上查看</span></span>\n<span class="line"><span>09:00 - 打开主会话（feat: 支付模块），恢复昨天的上下文</span></span>\n<span class="line"><span>09:15 - 用 Subagent 并行搜索代码库，收集需要修改的文件范围</span></span>\n<span class="line"><span>09:30 - 启动 Plan 模式，为今天的重构任务制定详细计划</span></span>\n<span class="line"><span>09:45 - 审核计划，调整两处细节</span></span>\n<span class="line"><span>10:00 - 按计划执行 Phase 1（数据层重构）</span></span>\n<span class="line"><span>10:45 - 收到 Cron 通知：CI 构建失败 → 切换到 Hotfix 会话</span></span>\n<span class="line"><span>11:00 - 在 Hotfix Worktree 中修复 CI 问题 → Commit → Push</span></span>\n<span class="line"><span>11:15 - 切回主会话，继续 Phase 2（API 层重构）</span></span>\n<span class="line"><span>12:00 - 上午工作结束。主会话的上下文完好保留</span></span>\n<span class="line"><span>14:00 - 下午：审查同事的 PR（切到 Review 会话）</span></span>\n<span class="line"><span>14:30 - 启动 Workflow：全面代码审查（3 个 Agent 并行）</span></span>\n<span class="line"><span>15:00 - 审查 Workflow 输出，标记 2 个 High 问题需要修复</span></span>\n<span class="line"><span>15:30 - 继续主会话的 Phase 3（前端层适配）</span></span>\n<span class="line"><span>16:30 - 所有 Phase 完成 → 进入 Plan 模式的 Phase 3 Review</span></span>\n<span class="line"><span>16:45 - 提交 PR，设置明天早上的 Cron 检查任务</span></span>\n<span class="line"><span>17:00 - 结束</span></span></code></pre></div><p>这不是&quot;理想化的未来&quot;，而是<strong>现在就可以做到的日常</strong>。你需要的只是知道这些能力的存在，并在实践中逐步将它们融入自己的工作流。</p><hr><p><strong>章节小结</strong>：本章开启了第七篇&quot;精通篇&quot;，系统介绍了六种 Claude Code 高级工作流能力——Subagent 多 Agent 协作、Plan 模式分阶段开发、多会话并行工作、Git Worktree 隔离开发、Cron 定时任务自动化、Workflow 编排。这六种能力的组合使用，将你的工作模式从&quot;线性单人协作&quot;升级为&quot;并行多人团队&quot;，实现 Claude Code 生产力的真正飞跃。下一章将深入 Claude Code 的扩展机制——自定义 Commands、Skills 和 Hooks 的开发。</p>',247))])}]]);export{l as __pageData,o as default};
